func (s *OrderServiceServer) CreateOrder(ctx context.Context, req *orderpb.CreateOrderRequest) (*orderpb.Order, error) {
	if req.UserId == "" {
		return nil, status.Errorf(codes.InvalidArgument, "user_id is required")
	}
	if len(req.Items) == 0 {
		return nil, status.Errorf(codes.InvalidArgument, "at least one item is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	id := fmt.Sprintf("order_%d", s.nextID)
	s.nextID++

	var totalAmount float64
	var orderItems []*orderpb.OrderItem
	for i, item := range req.Items {
		itemTotal := float64(item.Quantity) * item.UnitPrice
		totalAmount += itemTotal
		orderItems = append(orderItems, &orderpb.OrderItem{
			Id:          fmt.Sprintf("%s_item_%d", id, i+1),
			ProductId:   item.ProductId,
			ProductName: item.ProductName,
			Quantity:    item.Quantity,
			UnitPrice:   item.UnitPrice,
			TotalPrice:  itemTotal,
		})
	}

	order := &orderpb.Order{
		Id:              id,
		UserId:          req.UserId,
		Items:           orderItems,
		TotalAmount:     totalAmount,
		Currency:        req.Currency,
		Status:          orderpb.OrderStatus_ORDER_STATUS_PENDING,
		ShippingAddress: req.ShippingAddress,
		CreatedAt:       timestamppb.Now(),
		UpdatedAt:       timestamppb.Now(),
	}

	if order.Currency == "" {
		order.Currency = "USD"
	}

	s.orders[id] = order
	log.Printf("[OrderService] Created order: %s for user %s (total: %.2f %s)", id, req.UserId, totalAmount, order.Currency)
	return order, nil
}

func (s *OrderServiceServer) GetOrder(ctx context.Context, req *orderpb.GetOrderRequest) (*orderpb.Order, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "order id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	order, ok := s.orders[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}

	log.Printf("[OrderService] Retrieved order: %s", req.Id)
	return order, nil
}

func (s *OrderServiceServer) UpdateOrderStatus(ctx context.Context, req *orderpb.UpdateOrderStatusRequest) (*orderpb.Order, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "order id is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	order, ok := s.orders[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}

	// Validate state transitions
	validTransitions := map[orderpb.OrderStatus][]orderpb.OrderStatus{
		orderpb.OrderStatus_ORDER_STATUS_PENDING:    {orderpb.OrderStatus_ORDER_STATUS_CONFIRMED, orderpb.OrderStatus_ORDER_STATUS_CANCELLED},
		orderpb.OrderStatus_ORDER_STATUS_CONFIRMED:  {orderpb.OrderStatus_ORDER_STATUS_PROCESSING, orderpb.OrderStatus_ORDER_STATUS_CANCELLED},
		orderpb.OrderStatus_ORDER_STATUS_PROCESSING: {orderpb.OrderStatus_ORDER_STATUS_SHIPPED, orderpb.OrderStatus_ORDER_STATUS_CANCELLED},
		orderpb.OrderStatus_ORDER_STATUS_SHIPPED:    {orderpb.OrderStatus_ORDER_STATUS_DELIVERED},
		orderpb.OrderStatus_ORDER_STATUS_DELIVERED:   {orderpb.OrderStatus_ORDER_STATUS_REFUNDED},
	}

	allowed := false
	if transitions, exists := validTransitions[order.Status]; exists {
		for _, t := range transitions {
			if t == req.Status {
				allowed = true
				break
			}
		}
	}

	if !allowed {
		return nil, status.Errorf(codes.FailedPrecondition, "cannot transition from %s to %s", order.Status, req.Status)
	}

	order.Status = req.Status
	order.UpdatedAt = timestamppb.Now()
	if req.Reason != "" {
		order.StatusReason = req.Reason
	}

	log.Printf("[OrderService] Updated order %s status to %s", req.Id, req.Status)
	return order, nil
}

