func (s *PaymentServiceServer) CreatePayment(ctx context.Context, req *paymentpb.CreatePaymentRequest) (*paymentpb.Payment, error) {
	if req.OrderId == "" {
		return nil, status.Errorf(codes.InvalidArgument, "order_id is required")
	}
	if req.Amount <= 0 {
		return nil, status.Errorf(codes.InvalidArgument, "amount must be positive")
	}
	if req.Method == paymentpb.PaymentMethod_PAYMENT_METHOD_UNSPECIFIED {
		return nil, status.Errorf(codes.InvalidArgument, "payment method is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	// Check for duplicate payment for the same order
	for _, p := range s.payments {
		if p.OrderId == req.OrderId && p.Status == paymentpb.PaymentStatus_PAYMENT_STATUS_COMPLETED {
			return nil, status.Errorf(codes.AlreadyExists, "payment already completed for order %s", req.OrderId)
		}
	}

	id := fmt.Sprintf("pay_%d", s.nextID)
	s.nextID++

	payment := &paymentpb.Payment{
		Id:        id,
		OrderId:   req.OrderId,
		UserId:    req.UserId,
		Amount:    req.Amount,
		Currency:  req.Currency,
		Method:    req.Method,
		Status:    paymentpb.PaymentStatus_PAYMENT_STATUS_PENDING,
		CreatedAt: timestamppb.Now(),
		UpdatedAt: timestamppb.Now(),
	}

	if payment.Currency == "" {
		payment.Currency = "USD"
	}

	s.payments[id] = payment
	log.Printf("[PaymentService] Created payment: %s for order %s (%.2f %s)", id, req.OrderId, req.Amount, payment.Currency)
	return payment, nil
}

func (s *PaymentServiceServer) GetPayment(ctx context.Context, req *paymentpb.GetPaymentRequest) (*paymentpb.Payment, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "payment id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	payment, ok := s.payments[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.Id)
	}

	log.Printf("[PaymentService] Retrieved payment: %s", req.Id)
	return payment, nil
}

func (s *PaymentServiceServer) ProcessPayment(ctx context.Context, req *paymentpb.ProcessPaymentRequest) (*paymentpb.Payment, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "payment id is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	payment, ok := s.payments[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.Id)
	}

	if payment.Status != paymentpb.PaymentStatus_PAYMENT_STATUS_PENDING {
		return nil, status.Errorf(codes.FailedPrecondition, "payment %s is not in pending state (current: %s)", req.Id, payment.Status)
	}

	// Simulate payment processing
	log.Printf("[PaymentService] Processing payment %s...", req.Id)
	time.Sleep(100 * time.Millisecond) // Simulate processing delay

	// Simulate success/failure (in dev, always succeed unless amount > 10000)
	if payment.Amount > 10000 {
		payment.Status = paymentpb.PaymentStatus_PAYMENT_STATUS_FAILED
		payment.FailureReason = "amount exceeds limit for dev environment"
		log.Printf("[PaymentService] Payment %s failed: %s", req.Id, payment.FailureReason)
	} else {
		payment.Status = paymentpb.PaymentStatus_PAYMENT_STATUS_COMPLETED
		payment.TransactionId = fmt.Sprintf("txn_%s_%d", req.Id, time.Now().UnixNano())
		log.Printf("[PaymentService] Payment %s completed (txn: %s)", req.Id, payment.TransactionId)
	}

	payment.ProcessedAt = timestamppb.Now()
	payment.UpdatedAt = timestamppb.Now()

	return payment, nil
}

func (s *PaymentServiceServer) RefundPayment(ctx context.Context, req *paymentpb.RefundPaymentRequest) (*paymentpb.Payment, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "payment id is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	payment, ok := s.payments[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.Id)
	}

	if payment.Status != paymentpb.PaymentStatus_PAYMENT_STATUS_COMPLETED {
		return nil, status.Errorf(codes.FailedPrecondition, "can only refund completed payments (current: %s)", payment.Status)
	}

	refundAmount := req.Amount
	if refundAmount <= 0 || refundAmount > payment.Amount {
		refundAmount = payment.Amount
	}

	payment.Status = paymentpb.PaymentStatus_PAYMENT_STATUS_REFUNDED
	payment.RefundAmount = refundAmount
	payment.RefundReason = req.Reason
	payment.RefundedAt = timestamppb.Now()
	payment.UpdatedAt = timestamppb.Now()

	log.Printf("[PaymentService] Refunded payment %s (%.2f %s)", req.Id, refundAmount, payment.Currency)
	return payment, nil
}

