// ==================== Main Server ====================

func main() {
	port := ":50051"
	lis, err := net.Listen("tcp", port)
	if err != nil {
		log.Fatalf("Failed to listen on %s: %v", port, err)
	}

	// Create gRPC server with interceptors for development logging
	grpcServer := grpc.NewServer(
		grpc.UnaryInterceptor(loggingInterceptor),
	)

	// Register all service handlers
	userService := NewUserServiceServer()
	orderService := NewOrderServiceServer()
	paymentService := NewPaymentServiceServer()

	userpb.RegisterUserServiceServer(grpcServer, userService)
	orderpb.RegisterOrderServiceServer(grpcServer, orderService)
	paymentpb.RegisterPaymentServiceServer(grpcServer, paymentService)

	// Enable reflection for development and testing
	// This allows tools like grpcurl, grpcui, Postman, and Evans to discover services
	reflection.Register(grpcServer)

	log.Println("============================================")
	log.Println("  Microservices Development gRPC Server")
	log.Println("============================================")
	log.Printf("  Listening on %s", port)
	log.Println("  Reflection: ENABLED (dev mode)")
	log.Println("  Services:")
	log.Println("    - UserService")
	log.Println("    - OrderService")
	log.Println("    - PaymentService")
	log.Println("============================================")
	log.Println("  Test with grpcurl:")
	log.Printf("    grpcurl -plaintext localhost%s list", port)
	log.Printf("    grpcurl -plaintext localhost%s describe", port)
	log.Println("============================================")

	// Seed some dev data
	seedDevData(userService, orderService, paymentService)

	if err := grpcServer.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}

// loggingInterceptor logs all incoming RPC calls for development
func loggingInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	start := time.Now()
	log.Printf("[RPC] --> %s", info.FullMethod)

	resp, err := handler(ctx, req)

	duration := time.Since(start)
	if err != nil {
		st, _ := status.FromError(err)
		log.Printf("[RPC] <-- %s [%s] (%v) ERROR: %s", info.FullMethod, st.Code(), duration, st.Message())
	} else {
		log.Printf("[RPC] <-- %s [OK] (%v)", info.FullMethod, duration)
	}

	return resp, err
}

